package com.shecancode.product.model; import jakarta.persistence.*; import java.math.BigDecimal; @Entity public class Product { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false) private String name; @Column(length=1000) private String description; @Column(nullable=false) private BigDecimal price; private int stockQuantity; private boolean active=true; @ManyToOne(optional=false) private Category category; public Product(){} public Product(String n,String d,BigDecimal p,int s,Category c){name=n;description=d;price=p;stockQuantity=s;category=c;} public Long getId(){return id;} public String getName(){return name;} public void setName(String v){name=v;} public String getDescription(){return description;} public void setDescription(String v){description=v;} public BigDecimal getPrice(){return price;} public void setPrice(BigDecimal v){price=v;} public int getStockQuantity(){return stockQuantity;} public void setStockQuantity(int v){stockQuantity=v;} public boolean isActive(){return active;} public void setActive(boolean v){active=v;} public Category getCategory(){return category;} public void setCategory(Category v){category=v;} }